// // This T-type flip-flop toggles its output Q on a falling clock edge when the T input is low, while being set to HIGH when the reset input rst is HIGH.
module top_module(
	T,
	clk,
	Q,
	rst
);input T, clk, rst;
	output reg Q;

	always @(posedge clk)
	begin
	if(~rst)
		Q <= 1'b0;
	else if(T)
		Q <= ~Q;
	end

endmodule
